50:     // protocol inference for plaintext listeners. If ALPN data is available, it
51:     // is preferred, otherwise protocol inference is used. In almost all cases,
52:     // this is the right option to choose for this setting.
53:     AUTO = 0;
54: 
55:     // The connection manager will assume that the client is speaking HTTP/1.1.
56:     HTTP1 = 1;
57: 
58:     // The connection manager will assume that the client is speaking HTTP/2
59:     // (Envoy does not require HTTP/2 to take place over TLS or to use ALPN.
60:     // Prior knowledge is allowed).
61:     HTTP2 = 2;
62: 
