379:                                                  bool is_internally_created) {
380:   TRACE_EVENT("core", "ConnectionManagerImpl::newStream");
381:   if (connection_idle_timer_) {
382:     connection_idle_timer_->disableTimer();
383:   }
384: 
385:   ENVOY_CONN_LOG(debug, "new stream", read_callbacks_->connection());
386: 
387:   Buffer::BufferMemoryAccountSharedPtr downstream_stream_account =
388:       response_encoder.getStream().account();
389: 
390:   if (downstream_stream_account == nullptr) {
391:     // Create account, wiring the stream to use it for tracking bytes.
392:     // If tracking is disabled, the wiring becomes a NOP.
393:     auto& buffer_factory = dispatcher_->getWatermarkFactory();
394:     downstream_stream_account = buffer_factory.createAccount(response_encoder.getStream());
395:     response_encoder.getStream().setAccount(downstream_stream_account);
396:   }
397: 
398:   auto new_stream = std::make_unique<ActiveStream>(
399:       *this, response_encoder.getStream().bufferLimit(), std::move(downstream_stream_account));
400: 
401:   accumulated_requests_++;
402:   if (config_->maxRequestsPerConnection() > 0 &&
403:       accumulated_requests_ >= config_->maxRequestsPerConnection()) {
404:     if (codec_->protocol() < Protocol::Http2) {
405:       new_stream->filter_manager_.streamInfo().setShouldDrainConnectionUponCompletion(true);
406:       // Prevent erroneous debug log of closing due to incoming connection close header.
407:       drain_state_ = DrainState::Closing;
408:     } else if (drain_state_ == DrainState::NotDraining) {
409:       startDrainSequence();
410:     }
411:     ENVOY_CONN_LOG(debug, "max requests per connection reached", read_callbacks_->connection());
412:     stats_.named_.downstream_cx_max_requests_reached_.inc();
413:   }
414: 
415:   new_stream->state_.is_internally_created_ = is_internally_created;
416:   new_stream->response_encoder_ = &response_encoder;
417:   new_stream->response_encoder_->getStream().addCallbacks(*new_stream);
418:   new_stream->response_encoder_->getStream().registerCodecEventCallbacks(new_stream.get());
419:   new_stream->response_encoder_->getStream().setFlushTimeout(new_stream->idle_timeout_ms_);
420:   new_stream->streamInfo().setDownstreamBytesMeter(response_encoder.getStream().bytesMeter());
421:   // If the network connection is backed up, the stream should be made aware of it on creation.
422:   // Both HTTP/1.x and HTTP/2 codecs handle this in StreamCallbackHelper::addCallbacksHelper.
423:   ASSERT(read_callbacks_->connection().aboveHighWatermark() == false ||
424:          new_stream->filter_manager_.aboveHighWatermark());
